import{c as s,Q as a,j as i,m as n}from"./chunks/framework.D9IbVcwA.js";const k=JSON.parse('{"title":"006-mini-kernel-pmm-2 · 物理内存管理","description":"","frontmatter":{"title":"006-mini-kernel-pmm-2 · 物理内存管理"},"headers":[],"relativePath":"tutorial/006-mini-kernel-pmm-2.md","filePath":"tutorial/006-mini-kernel-pmm-2.md","lastUpdated":1779686691000}'),t={name:"tutorial/006-mini-kernel-pmm-2.md"};function l(d,e,o,r,p,c){return a(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="踩坑实录-链接器符号与入口点——两个差点让我放弃的-bug" tabindex="-1">踩坑实录：链接器符号与入口点——两个差点让我放弃的 Bug <a class="header-anchor" href="#踩坑实录-链接器符号与入口点——两个差点让我放弃的-bug" aria-label="Permalink to &quot;踩坑实录：链接器符号与入口点——两个差点让我放弃的 Bug&quot;">​</a></h1><blockquote><p>标签：链接器符号、入口点、全局构造函数、debugcon、对象库 前置：<a href="./006-mini-kernel-pmm-1">006-1 从零开始的物理内存管理</a></p></blockquote><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>说实话，这一章写起来最痛苦的部分不是 PMM 本身——位图分配器逻辑清晰、代码直白，一个下午就能搞定。真正让我血压拉满的是两个隐藏极深的坑：链接器符号的访问陷阱，以及 CMake 对象库引发的入口点偏移 bug。第一个坑让我对着 <code>kernel_size = 0</code> 的串口输出发呆了两个小时，第二个坑更离谱——串口完全没输出，我一度以为是 QEMU 坏了或者 bootloader 把内核加载到了错误的地方。</p><p>这两个 bug 的共同特点是：代码编译完全通过，没有任何警告，但运行时行为完全错误。它们不属于&quot;语法错误&quot;或&quot;逻辑错误&quot;这种教科书式的分类，而是横跨 C++、链接器、CMake 三个系统的&quot;跨界 Bug&quot;。如果你也在写内核、也在用链接器符号、也在用 CMake 对象库，这篇文章可能帮你省掉好几个不眠之夜。</p><p>在正式开始踩坑之前，先交代一下调试方法论。内核调试和用户态程序调试完全不同——你不能 <code>printf</code>（因为可能连输出设备都没初始化）、不能 <code>gdb attach</code>（因为内核本身就是调试器运行的平台）、不能 <code>strace</code>（因为没有系统调用）。你能依赖的只有两样东西：QEMU 的 debugcon 端口（0xE9，向它 <code>outb</code> 一个字节就会写入日志文件，不需要任何硬件初始化）和 QEMU + GDB 的远程调试（<code>-s -S</code> 启动，GDB 通过 <code>target remote :1234</code> 连接）。掌握了这两个工具，你在内核调试中就不会完全抓瞎。</p><h2 id="环境说明" tabindex="-1">环境说明 <a class="header-anchor" href="#环境说明" aria-label="Permalink to &quot;环境说明&quot;">​</a></h2><p>这个 debug 过程在 QEMU 128MB 配置下进行，使用 <code>-debugcon file:debug.log</code> 捕获 debugcon 端口输出，<code>-serial stdio</code> 获取串口输出。内核链接在 higher-half 地址 <code>0xFFFFFFFF80000000</code>，物理加载地址 <code>0x20000</code>。bootloader 硬编码跳转到 <code>0xFFFFFFFF80020000</code>（虚拟地址），这个地址被假定是 <code>_start</code> 函数的位置。调试工具只有 <code>nm</code>（查看符号表）、<code>objdump</code>（反汇编）、<code>readelf</code>（查看 ELF 头）和 debugcon 字符输出。</p><h2 id="第一个坑-链接器符号不是变量" tabindex="-1">第一个坑：链接器符号不是变量 <a class="header-anchor" href="#第一个坑-链接器符号不是变量" aria-label="Permalink to &quot;第一个坑：链接器符号不是变量&quot;">​</a></h2><h3 id="事情是怎么开始的" tabindex="-1">事情是怎么开始的 <a class="header-anchor" href="#事情是怎么开始的" aria-label="Permalink to &quot;事情是怎么开始的&quot;">​</a></h3><p>PMM 的初始化流程中需要知道内核自身占用了多少物理内存，以便把相应的页标记为&quot;已用&quot;。链接器脚本 <code>linker.ld</code> 中定义了 <code>__kernel_size</code> 符号，计算方式是 <code>__mini_kernel_end - (KERNEL_Virt_BASE + KERNEL_PHYS_BASE)</code>。我用 <code>nm</code> 确认了符号的值是 <code>0x42F0</code>（约 17KB），看起来没问题。</p><p>然后我在 C++ 代码里这么写的：</p><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">extern</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;C&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    extern</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> uint64_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> __kernel_size;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">uint64_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> size </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> __kernel_size;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 读到的竟然是 0！</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>编译通过，链接通过，没有任何错误和警告。但串口输出显示 <code>kernel_size = 0</code>。我反复确认链接器脚本的计算是正确的，<code>nm</code> 也显示符号值确实是 <code>0x42F0</code>。那为什么 C++ 代码读到的是 0？</p><h3 id="根因-链接器符号是地址常量" tabindex="-1">根因：链接器符号是地址常量 <a class="header-anchor" href="#根因-链接器符号是地址常量" aria-label="Permalink to &quot;根因：链接器符号是地址常量&quot;">​</a></h3><p>问题的根源在于对链接器符号本质的误解。链接器脚本中的符号（如 <code>__kernel_size = expr</code>）不是变量——链接器不会在内存中分配空间来存储它的值。它只是符号表中的一个条目，记录了一个地址值。当你声明 <code>extern uint64_t __kernel_size</code> 并访问 <code>__kernel_size</code> 时，C++ 编译器生成的代码是这样的：去符号表找到 <code>__kernel_size</code> 的地址，然后读取该地址处的 8 字节内存内容。</p><p>但这个地址处根本没有任何有效数据！链接器没有在这里存放任何东西。这个地址可能落在 <code>.text</code> 段的某个位置、也可能落在 <code>.bss</code> 段的某个位置，里面存的是什么完全取决于这段内存碰巧被初始化成了什么。在我的案例中，它恰好是 0（因为那个地址落在 BSS 段，BSS 被 <code>rep stosb</code> 清零了）。</p><p>正确的做法是声明为 <code>char</code> 类型（最小可取地址类型），然后取地址：</p><div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">extern</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;C&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    extern</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> char</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> __kernel_size;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     // 类型不重要，能取地址就行</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">uint64_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> size </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> reinterpret_cast&lt;uint64_t&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">__kernel_size);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 取地址才是值</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><code>&amp;__kernel_size</code> 获取的是符号的地址——对于链接器符号来说，地址本身就是它所代表的值。这是 OSDev Wiki 的 <a href="https://wiki.osdev.org/Writing_A_Page_Frame_Allocator" target="_blank" rel="noreferrer">Writing A Page Frame Allocator</a> 页面也提到的经典模式：链接器符号 <code>endkernel</code> 的访问方式是取地址而非直接读取。你可以用 <code>nm</code> 验证这一点：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build/kernel/mini/mini_kernel</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> __kernel_size</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 输出: 00000000000042f0 A __kernel_size</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#                ^^^^^^^^ 这就是你要的值</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#                          ^ A = absolute symbol</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>类型 <code>A</code> 表示这是一个绝对符号，它的值不随重定位改变。这也印证了它不是一个真正的变量——变量会有类型 <code>B</code>（BSS 段）或 <code>D</code>（数据段）。</p><h3 id="更深层的原因-链接器符号-vs-c-变量" tabindex="-1">更深层的原因：链接器符号 vs C 变量 <a class="header-anchor" href="#更深层的原因-链接器符号-vs-c-变量" aria-label="Permalink to &quot;更深层的原因：链接器符号 vs C 变量&quot;">​</a></h3><p>理解这个 bug 的关键在于区分两种完全不同的&quot;符号&quot;概念。在 C/C++ 程序员的眼中，<code>extern int foo</code> 声明了一个变量，这个变量存在于内存中的某个位置，你可以读写它的值。但链接器眼中的&quot;符号&quot;更广泛——它只是符号表中的一个键值对，键是符号名（如 <code>__kernel_size</code>），值是一个地址（如 <code>0x42F0</code>）。链接器不关心这个地址处有没有数据、数据是什么类型——它只负责记录&quot;这个符号名对应这个地址值&quot;。</p><p>当你用 <code>extern uint64_t __kernel_size</code> 声明并直接访问时，编译器生成代码&quot;读取地址 0x42F0 处的 8 个字节&quot;。但 0x42F0 是一个地址值，不是一块存储了内核大小的内存区域——它可能落在 <code>.text</code> 段（读到的是指令编码的一部分）、可能落在 <code>.bss</code> 段（读到的是 0），取决于链接器把 <code>__kernel_size</code> 符号安排在了哪个地址。这就是为什么取地址（<code>&amp;__kernel_size</code>）才是正确的方式——取地址操作直接返回符号表中记录的值，而不是去读取该地址处的内存。</p><h3 id="这个坑为什么特别危险" tabindex="-1">这个坑为什么特别危险 <a class="header-anchor" href="#这个坑为什么特别危险" aria-label="Permalink to &quot;这个坑为什么特别危险&quot;">​</a></h3><p>这个 bug 之所以难以发现，是因为它在大多数情况下不会导致崩溃。如果链接器符号恰好落在 <code>.text</code> 段内，直接访问会读到指令编码的一部分——一个看起来像随机数的非零值。你可能会误以为 PMM 工作正常，但内核大小是错的，导致某些页被错误地标记为可用或已用。只有在符号恰好落在 BSS 段（被清零）时，你才会得到 0 这个明显的错误值。所以如果你看到内核大小是 0 或者一个离谱的巨大数字，第一时间检查链接器符号的访问方式。</p><h2 id="第二个坑-cmake-对象库的链接顺序" tabindex="-1">第二个坑：CMake 对象库的链接顺序 <a class="header-anchor" href="#第二个坑-cmake-对象库的链接顺序" aria-label="Permalink to &quot;第二个坑：CMake 对象库的链接顺序&quot;">​</a></h2><h3 id="事情是怎么开始的-1" tabindex="-1">事情是怎么开始的 <a class="header-anchor" href="#事情是怎么开始的-1" aria-label="Permalink to &quot;事情是怎么开始的&quot;">​</a></h3><p>在解决了链接器符号的问题后，PMM 代码终于能编译了。我满怀期待地启动 QEMU——然后什么都没有。串口没有输出，debugcon 日志是空的。我甚至一度怀疑是不是忘记编译了，反复检查了构建命令。最后我把问题简化到最小：注释掉 PMM 代码，只保留最基本的串口输出。结果还是没输出。</p><p>这意味着问题不在 PMM 代码本身，而在更底层的地方。</p><h3 id="用-debugcon-逐步追踪" tabindex="-1">用 debugcon 逐步追踪 <a class="header-anchor" href="#用-debugcon-逐步追踪" aria-label="Permalink to &quot;用 debugcon 逐步追踪&quot;">​</a></h3><p>QEMU 的 debugcon 端口（<code>0xE9</code>）是内核调试的救命稻草——它不依赖任何硬件初始化，CPU 执行的第一条指令就可以用它。我在 <code>boot.S</code> 的 <code>_start</code> 函数中放了四个字符标记：<code>&#39;1&#39;</code>（进入 _start）、<code>&#39;2&#39;</code>（栈就绪）、<code>&#39;3&#39;</code>（BSS 清零完成）、<code>&#39;4&#39;</code>（全局构造函数调用完成）。在 <code>_init_global_ctors</code> 中放了 <code>&#39;{&#39;</code> 和 <code>&#39;}&#39;</code>。在 Serial 构造函数中放了 <code>&#39;C&#39;</code>。</p><p>启动 QEMU 后检查 debugcon 日志——完全空白。这意味着 <code>_start</code> 根本没有执行。</p><h3 id="发现-entry-point-偏移" tabindex="-1">发现 entry point 偏移 <a class="header-anchor" href="#发现-entry-point-偏移" aria-label="Permalink to &quot;发现 entry point 偏移&quot;">​</a></h3><p>bootloader 在 <code>stage2.S</code> 中硬编码了跳转地址：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">movq</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $0xFFFFFFFF80020000, %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rax</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">call</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> *%</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rax</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>它期望 <code>0xFFFFFFFF80020000</code> 处是 <code>_start</code>。我用 <code>readelf</code> 检查内核的 entry point：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">readelf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build/kernel/mini/mini_kernel</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Entry</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 输出: Entry point address: 0xffffffff8002012a</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>0x8002012a</code> 而不是 <code>0x80020000</code>！差了 <code>0x12a</code> 字节。bootloader 跳到了 <code>0x80020000</code>，但那里已经不是 <code>_start</code> 了。我反汇编看了一下那个地址：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">objdump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build/kernel/mini/mini_kernel</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;80020000:&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 输出: ffffffff80020000:  55  push   %rbp</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>push %rbp</code> 是函数序言的典型指令。这个地址处是 <code>mini_kernel_main</code> 的开头——bootloader 跳过了 <code>_start</code>，直接跑进了 <code>mini_kernel_main</code>。于是 BSS 没被清零、全局构造函数没被调用、<code>g_serial</code> 对象的 <code>base_port</code> 成员是 0，串口驱动卡在死循环里。</p><h3 id="根因-cmake-对象库改变了链接顺序" tabindex="-1">根因：CMake 对象库改变了链接顺序 <a class="header-anchor" href="#根因-cmake-对象库改变了链接顺序" aria-label="Permalink to &quot;根因：CMake 对象库改变了链接顺序&quot;">​</a></h3><p>之前代码用的是 CMake 静态库（STATIC library），链接器从 <code>.a</code> 文件中提取 <code>.o</code> 时，<code>_start</code> 所在的 <code>boot.o</code> 恰好被排在了最前面。切换到对象库（OBJECT library）后，CMake 传递 <code>.o</code> 文件给链接器的顺序变了，<code>boot.o</code> 不再是第一个，导致 <code>_start</code> 不在 <code>.text</code> 段的开头。</p><p>这个 bug 的诡异之处在于：内核代码&quot;能运行&quot;——它跑进了 <code>mini_kernel_main</code>，E820 信息可以打印，看起来一切正常。但全局构造函数没被调用，所有依赖构造函数初始化的全局对象都处于未初始化状态。这个 bug 只在特定的链接顺序下才会触发，而且不一定会导致崩溃——可能只是某些全局变量值不对，藏在暗处等你发现。</p><h3 id="修复-专用段保证入口点位置" tabindex="-1">修复：专用段保证入口点位置 <a class="header-anchor" href="#修复-专用段保证入口点位置" aria-label="Permalink to &quot;修复：专用段保证入口点位置&quot;">​</a></h3><p>修复分两步。第一步在链接器脚本中添加一个专用的 <code>.text.start</code> 段：</p><div class="language-makefile vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">makefile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : AT(ADDR(.text) - KERNEL_Virt_BASE) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    *(.text.start)        /* _start 必须在最前面! */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    *(.text .text.*)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    *(.rodata .rodata.*)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>链接器按通配符出现的顺序处理输入段，所以 <code>.text.start</code> 中的内容永远被放在 <code>.text</code> 输出段的最前面。</p><p>第二步在 <code>boot.S</code> 中把 <code>_start</code> 放进这个专用段：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">section .text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.start, &quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ax</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.code64</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.global</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> _start</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.type _start, @function</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">_start:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    cli</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    /* ... */</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>修复后验证：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">readelf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build/kernel/mini/mini_kernel</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Entry point&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 输出: Entry point address: 0xffffffff80020000</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 现在对了！</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">objdump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build/kernel/mini/mini_kernel</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -3</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ffffffff80020000 &lt;_start&gt;:</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ffffffff80020000:  fa  cli</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># _start 确实在正确地址</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>debugcon 日志也恢复了正常：<code>1234{...}C...J...</code>，完整的启动流程标记都在。</p><h3 id="修复的精妙之处" tabindex="-1">修复的精妙之处 <a class="header-anchor" href="#修复的精妙之处" aria-label="Permalink to &quot;修复的精妙之处&quot;">​</a></h3><p>这个修复方案的巧妙之处在于它不改变任何代码逻辑——只是把 <code>_start</code> 放到了一个有专用名字的段（<code>.text.start</code>）中。链接器脚本按通配符出现的顺序处理输入段，所以 <code>.text.start</code> 永远排在 <code>.text</code> 前面。这意味着不管 CMake 怎么排列 <code>.o</code> 文件的顺序，不管编译器怎么优化函数布局，<code>_start</code> 永远占据 <code>.text</code> 输出段的第一个位置。</p><p>Linux 内核也用了完全相同的技巧——它的 <code>arch/x86/kernel/vmlinux.lds.S</code> 链接脚本中定义了 <code>.head.text</code> 段，<code>startup_64</code> 函数通过 <code>.section .head.text</code> 放在这个段中。如果你去看其他 OS 项目，会发现这种&quot;专用段保证入口点位置&quot;的模式非常普遍。</p><h3 id="和其他项目的对比" tabindex="-1">和其他项目的对比 <a class="header-anchor" href="#和其他项目的对比" aria-label="Permalink to &quot;和其他项目的对比&quot;">​</a></h3><p>这个问题在 OS 社区中并不罕见。Linux 内核通过在链接器脚本中显式指定 <code>.head.text</code> 段来保证内核入口点（<code>startup_64</code>）的位置，和我们的 <code>.text.start</code> 方案在思路上完全一致。xv6 更简单——它的入口点直接写在 <code>entry.S</code> 中，链接器脚本用 <code>ENTRY(entry)</code> 指定入口符号，bootloader（<code>bootmain.c</code>）从 ELF header 的 <code>e_entry</code> 字段读取入口地址，所以链接顺序不会造成问题。SerenityOS 的 bootloader（<code>Bootloader/BootDDRELFLoader.cpp</code>）同样解析 ELF header 获取入口点，避免了硬编码地址的脆弱性。</p><p>说到底，我们的问题的根源是 bootloader 硬编码了跳转地址。更健壮的做法是让 bootloader 解析 ELF header 中的 <code>e_entry</code> 字段——这是 xv6 和 SerenityOS 都采用的方式。但在当前的 flat binary 加载模式下（<code>objcopy -O binary</code> 把 ELF 转成了裸二进制），ELF header 在运行时已经不存在了，所以硬编码地址是唯一的选择。<code>.text.start</code> 段的修复方案在当前约束下是最合理的。</p><h3 id="为什么不用-entry-指令" tabindex="-1">为什么不用 <code>ENTRY()</code> 指令 <a class="header-anchor" href="#为什么不用-entry-指令" aria-label="Permalink to &quot;为什么不用 \`ENTRY()\` 指令&quot;">​</a></h3><p>你可能会问：链接器脚本不是有 <code>ENTRY(_start)</code> 指令吗？它不就能告诉链接器入口点在哪吗？<code>ENTRY()</code> 确实会设置 ELF 文件的 <code>e_entry</code> 字段，但这个字段只在 ELF 格式下有意义。我们的 bootloader 使用的是 <code>objcopy -O binary</code> 生成 flat binary——这个过程中 ELF header 被剥离，<code>e_entry</code> 信息丢失了。bootloader 只是把 flat binary 加载到固定地址然后跳转，它无法从二进制文件中获取入口点信息。</p><p>所以 <code>.text.start</code> 段方案的本质是：既然 bootloader 硬编码了跳转地址 <code>0xFFFFFFFF80020000</code>，那我们就通过链接脚本保证这个地址处一定是 <code>_start</code>。这是一种&quot;约定大于配置&quot;的设计——bootloader 和内核通过一个隐含的约定（<code>.text</code> 段的第一个字节是 <code>_start</code>）来协作。</p><h2 id="收尾" tabindex="-1">收尾 <a class="header-anchor" href="#收尾" aria-label="Permalink to &quot;收尾&quot;">​</a></h2><p>这两个 bug 给我上了生动的一课：内核开发中，&quot;编译通过&quot;完全不等于&quot;代码正确&quot;。链接器符号的访问陷阱和对象库的链接顺序问题，都不会在编译期产生任何错误或警告。它们只在运行时表现出诡异的行为——一个让你读到 0 的内核大小，一个让你完全没输出的串口。debugcon 端口（<code>outb %al, $0xE9</code>）在这种时候就是救命工具，它让你能在没有任何基础设施的情况下追踪执行流程。</p><h3 id="调试方法论总结" tabindex="-1">调试方法论总结 <a class="header-anchor" href="#调试方法论总结" aria-label="Permalink to &quot;调试方法论总结&quot;">​</a></h3><p>回顾这两个 bug 的调试过程，可以总结出一套通用的内核调试方法论。当内核行为异常时，按以下优先级排查：</p><ol><li><strong>debugcon 标记法</strong>：在关键函数入口输出字符标记。如果标记没出现，说明函数没被执行——从后往前追溯执行路径。</li><li><strong>entry point 检查</strong>：<code>readelf -h kernel | grep Entry</code> 确认 ELF 入口点地址。如果和你期望的不一样，说明链接/加载过程出了问题。</li><li><strong>符号表检查</strong>：<code>nm kernel | grep symbol_name</code> 确认符号是否存在、值是否正确、类型是否匹配（A=绝对、B=BSS、D=数据、T=代码）。</li><li><strong>段布局检查</strong>：<code>objdump -d kernel | head</code> 查看代码段的起始内容，确认函数位置是否符合预期。</li><li><strong>init_array 检查</strong>：<code>objdump -s -j .init_array kernel</code> 查看全局构造函数指针是否存在。</li></ol><p>这套方法不需要任何高级调试工具，只需要 <code>readelf</code>、<code>nm</code>、<code>objdump</code> 和 QEMU 的 debugcon 端口，在任何开发环境下都能使用。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>OSDev Wiki: <a href="https://wiki.osdev.org/Writing_A_Page_Frame_Allocator" target="_blank" rel="noreferrer">Writing A Page Frame Allocator</a> — 链接器符号 <code>endkernel</code> 的正确访问方式</li><li>OSDev Wiki: <a href="https://wiki.osdev.org/Linker_Scripts" target="_blank" rel="noreferrer">Linker Scripts</a> — 链接脚本中段放置规则</li><li>LD Manual: <a href="https://sourceware.org/binutils/docs/ld/Simple-Assignments.html" target="_blank" rel="noreferrer">Simple Assignments</a> — 链接器符号赋值的语义</li><li>LD Manual: <a href="https://sourceware.org/binutils/docs/ld/SECTIONS.html" target="_blank" rel="noreferrer">SECTIONS Command</a> — 段通配符的匹配顺序</li><li>Linux kernel: <code>arch/x86/kernel/vmlinux.lds.S</code> — <code>.head.text</code> 段的使用</li><li>xv6: <code>kernel/entry.S</code> + <code>kernel/kernel.ld</code> — <code>ENTRY(entry)</code> 指定入口符号</li></ul>`,71)])])}const b=s(t,[["render",l]]);export{k as __pageData,b as default};
